sql:
SELECT AVG(execution_time_ms) AS average_execution_time
FROM performance_logs
WHERE thread_id IN (SELECT DISTINCT thread_id FROM alerts);

SELECT COUNT(*) AS total_critical_alerts
FROM alerts
WHERE alert_level = 'critical';

SELECT DISTINCT thread_id
FROM alerts
WHERE alert_level = 'critical';

SELECT COUNT(*) 
FROM threads 
WHERE application_id = 123 AND status = 'running';

SELECT AVG(execution_time_ms) AS average_execution_time_ms
FROM performance_logs
WHERE application_id = 1;

SELECT COUNT(*) AS thread_count
FROM threads
WHERE thread_type = 'worker';

SELECT application_id, COUNT(thread_id) AS total_threads
FROM threads
GROUP BY application_id;

SELECT log_id, log_timestamp, execution_time_ms, cpu_usage, memory_usage
FROM performance_logs
ORDER BY execution_time_ms DESC;

external_knowledge:
- 'typical performance' refers to the average execution time of threads for each application;
- 'stability issues' or 'glitches' are synonymous with the number of error logs per application;
- 'runtime' is equivalent to execution time in milliseconds.

sql:
SELECT log_id, execution_time_ms, cpu_usage
FROM performance_logs
ORDER BY execution_time_ms DESC;

SELECT application_name
FROM applications
ORDER BY application_name;

SELECT pl.application_id, AVG(pl.execution_time_ms) AS average_execution_time
FROM performance_logs pl
WHERE pl.execution_time_ms > (
    SELECT AVG(execution_time_ms) FROM performance_logs
)
GROUP BY pl.application_id;
